const LANG_INDEX: Record<Lang, number> = { EN: 0, DE: 1, NL: 2, FR: 3, ES: 4, IT: 5 } as any;

// tr metnini seçili dile çevirir. TR ise olduğu gibi döner.
export function appT(lang: Lang, tr: string): string {
  if (lang === "TR") return tr;
  const row = T[tr];
  if (!row) return tr; // sözlükte yoksa TR'yi göster (güvenli)
  return row[LANG_INDEX[lang]] ?? tr;
}
